<?php require_once 'mailer.php'; $u=require_login('student'); verify_csrf(); $tableId=(int)($_GET['table_id']??$_POST['table_id']??0); $days=(int)($_GET['days']??$_POST['days']??30); $amount=setting_price($days); if(!$tableId||!$amount||active_overlap_exists($tableId)){ flash('Selected table is unavailable.','err'); header('Location: table_booking.php'); exit; } if($_SERVER['REQUEST_METHOD']==='POST'){ $tx=trim($_POST['transaction_id']??''); if(!preg_match('/^[A-Za-z0-9._-]{6,120}$/',$tx)) flash('Enter a valid transaction ID.','err'); else try{ pdo()->beginTransaction(); $s=pdo()->prepare("SELECT COUNT(*) FROM bookings WHERE table_id=? AND status='accepted' AND expiry_date>=CURDATE() FOR UPDATE"); $s->execute([$tableId]); if($s->fetchColumn()) throw new Exception('Table already booked.'); $b=pdo()->prepare('INSERT INTO bookings(student_id,table_id,duration_days,amount,status) VALUES(?,?,?,?,"pending")'); $b->execute([$u['id'],$tableId,$days,$amount]); $bid=pdo()->lastInsertId(); pdo()->prepare('INSERT INTO payments(booking_id,transaction_id,method,amount,status) VALUES(?,?,?,? ,"pending")')->execute([$bid,$tx,$_POST['method']??'UPI_QR',$amount]); pdo()->commit(); email_payment_pending($u,(int)$bid); flash('Payment submitted. Booking is pending librarian approval.'); header('Location: pending.php'); exit; }catch(Throwable $e){ if(pdo()->inTransaction()) pdo()->rollBack(); flash('Payment submission failed. Transaction ID may already exist.','err'); }} $upi='upi://pay?pa='.rawurlencode(UPI_ID).'&pn='.rawurlencode(PAYEE_NAME).'&am='.$amount.'&cu='.CURRENCY.'&tn='.rawurlencode('Library table booking'); $qr=QR_PROVIDER.'?size=260x260&data='.rawurlencode($upi); app_header('Payment'); ?><section class="pay card"><h1>UPI Payment</h1><p>Amount: <b>₹<?=e($amount)?></b> for <?=e($days)?> days</p><img class="qr" src="<?=e($qr)?>" alt="Dynamic UPI QR"><p><?=e(UPI_ID)?> • <?=e(PAYEE_NAME)?></p><form method="post"><?=csrf_field()?><input type="hidden" name="table_id" value="<?=e($tableId)?>"><input type="hidden" name="days" value="<?=e($days)?>"><select name="method"><option value="UPI_QR">UPI QR</option><option value="DYNAMIC_QR">Dynamic QR</option></select><input name="transaction_id" placeholder="Transaction ID / UTR" required><button class="btn">Submit for approval</button></form></section><?php app_footer(); ?>
